const staticData = $getWorkflowStaticData('global');
if (!staticData.processedKeys) {
  staticData.processedKeys = {};
}

const recordKey = String($input.item.json.record_key).trim().toLowerCase();

// Check if key exists
const isDuplicate = staticData.processedKeys[recordKey] !== undefined;

// Reserve the slot immediately to prevent same-batch race conditions
if (!isDuplicate) {
  staticData.processedKeys[recordKey] = 'reserved';
}

return [{
  json: {
    ...$input.item.json,
    duplicate: isDuplicate
  }
}];

const input = $input.item.json;
const result = (input.organic_results && input.organic_results[0]) || {};

const rawTitle = result.title || '';
let cleanTitle = rawTitle;
const link = result.link || '';
const snippet = result.snippet || '';


// Regex to capture everything between "- " and " at"
const match = rawTitle.match(/-\s+(.*?)\s+at/);

if (match && match[1]) {
  cleanTitle = match[1].trim();
} else {
  // Fallback: If " at" isn't found, just grab everything after the dash
  const dashIndex = rawTitle.indexOf('-');
  if (dashIndex !== -1) {
    cleanTitle = rawTitle.substring(dashIndex + 1).split(' at')[0].trim();
  }
}

return [{
  json: {
    run_id: $('Set run ID').item.json.run_id,
    record_key: $('Set run ID').item.json.record_key,
    name: $('Set run ID').item.json.name,
    company: $('Set run ID').item.json.company,
    title: cleanTitle, // Now returns "Financial Crime"
    link: link,
    snippet: snippet,
    processed_at: $now.toISO()
  }
}];
